#include<bits/stdc++.h>
using namespace std;
int a[21][21],i,j;
int main() {
	int n;
	cin>>n;
	for(i=0;i<n;i++){
	
	
		for(j=i;j<n;j++){
			if(i==0){
				a[j][i]=1;
			}else{
				a[j][i]=a[j-1][i]+a[j-1][i-1];
			}
			
		}
		
		
	}
	for (i = 0; i <n; i++) {
		for (j = 0; j <= i; j++) {
			cout << a[i][j]<<" ";

		}
		cout << endl;
	}
	return 0;
}
